import React, { useState, useEffect } from "react";
import axios from "axios";
import "./styles.css";

function App() {
  const [message, setMessage] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Gọi API từ backend
    axios
      .get("http://localhost:3000/api/fpgrowth") // Cập nhật đúng endpoint của bạn
      .then((response) => {
        setMessage(response.data.message); // Hiển thị thông điệp từ server
        setLoading(false);
      })
      .catch((error) => {
        console.error("There was an error calling the API!", error);
        setLoading(false);
      });
  }, []);

  return (
    <div className="App">
      <h1>Phân tích hành vi mua sắm của khách hàng</h1>
      {loading ? <p>Đang tải dữ liệu...</p> : <p>{message}</p>}
    </div>
  );
}

export default App;
